for attachment in records:
    if attachment.mimetype in ('application/pdf', 'image/png', 'image/jpeg', 'image/tiff'):
        env['ipai.ai.job'].create({
            'source_model': attachment.res_model or 'ir.attachment',
            'source_record_id': attachment.res_id or attachment.id,
            'source_record_name': attachment.name,
            'job_type': 'ocr_extract',
            'trigger': 'manual',
            'attachment_id': attachment.id,
        })

for record in records:
    action = {
        'type': 'ir.actions.client',
        'tag': 'ipai_copilot_open',
        'params': {
            'model': 'account.move',
            'res_id': record.id,
            'action': 'ask',
        },
    }

for record in records:
